import "@/App.css";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
  Outlet,
} from "react-router-dom";

import axios from "axios";
import { useMemo } from "react";
import { Toaster } from "@/components/ui/sonner";

// ======================
// PUBLIC PAGES
// ======================
import LandingPage from "@/pages/LandingPage";
import SchoolProfilePage from "@/pages/SchoolProfilePage";

// ======================
// AUTH PAGES
// ======================
import LoginPage from "@/pages/LoginPage";
import RegisterPage from "@/pages/RegisterPage";
import JoinSchoolPage from "@/pages/JoinSchoolPage";

// ======================
// DASHBOARD LAYOUT
// ======================
import DashboardLayout from "@/components/layouts/DashboardLayout";

// ======================
// CORE MODULES
// ======================
import Dashboard from "@/pages/Dashboard";
import StudentsPage from "@/pages/StudentsPage";
import StaffPage from "@/pages/StaffPage";
import FeesPage from "@/pages/FeesPage";
import AttendancePage from "@/pages/AttendancePage";
import ExamsPage from "@/pages/ExamsPage";
import TimetablePage from "@/pages/TimetablePage";
import InventoryPage from "@/pages/InventoryPage";

// ======================
// PORTALS
// ======================
import StudentPortal from "@/pages/StudentPortal";
import TeacherPortal from "@/pages/TeacherPortal";
import FinancePortal from "@/pages/FinancePortal";
import SecretaryPortal from "@/pages/SecretaryPortal";

// ======================
// ADMIN
// ======================
import SuperAdminDashboard from "@/pages/SuperAdminDashboard";
import AnnouncementsPage from "@/pages/AnnouncementsPage";

// ======================
// NEW LOGIN PORTAL
// ======================
import LoginPortalPage from "@/pages/LoginPortalPage";

// ======================
// DEBUG
// ======================
import DataExplorer from "@/pages/DataExplorer";

// ======================
// BACKEND CONFIG
// ======================
const BACKEND_URL =
  process.env.REACT_APP_BACKEND_URL || "http://localhost:8000";

export const API = `${BACKEND_URL.replace(/\/$/, "")}/api`;

// ======================
// ROLE NORMALIZER
// ======================
const normalizeRole = (role) => {
  if (!role) return "";

  const normalized = String(role)
    .trim()
    .toUpperCase();

  const roleMap = {
    ADMIN: "SCHOOL_ADMIN",
    SCHOOLADMIN: "SCHOOL_ADMIN",
    SCHOOL_ADMIN: "SCHOOL_ADMIN",

    SUPERADMIN: "SUPER_ADMIN",
    SUPER_ADMIN: "SUPER_ADMIN",

    TEACHER: "TEACHER",
    SECRETARY: "SECRETARY",
    FINANCE: "FINANCE",
    STUDENT: "STUDENT",
    PARENT: "PARENT",
  };

  return roleMap[normalized] || normalized;
};

// ======================
// AUTH SERVICE
// ======================
export const authService = {
  getToken: () => {
    try {
      return localStorage.getItem("token");
    } catch {
      return null;
    }
  },

  getUser: () => {
    try {
      const user = localStorage.getItem("user");

      if (!user || user === "undefined") {
        return null;
      }

      const parsed = JSON.parse(user);

      return {
        ...parsed,
        role: normalizeRole(parsed?.role),
      };
    } catch (error) {
      console.error("Failed to parse user:", error);
      return null;
    }
  },

  setAuth: (token, user) => {
    if (!token || !user) return;

    const safeUser = {
      ...user,
      role: normalizeRole(user?.role),
    };

    localStorage.setItem("token", token);
    localStorage.setItem(
      "user",
      JSON.stringify(safeUser)
    );
  },

  clearAuth: () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
  },

  isAuthenticated: () => {
    return !!localStorage.getItem("token");
  },

  getRole: () => {
    const user = authService.getUser();

    return normalizeRole(user?.role);
  },
};

// ======================
// AXIOS CLIENT
// ======================
export const apiClient = axios.create({
  baseURL: API,
  timeout: 30000,
});

// ======================
// REQUEST INTERCEPTOR
// ======================
apiClient.interceptors.request.use(
  (config) => {
    const token = authService.getToken();

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    config.headers["Content-Type"] =
      "application/json";

    return config;
  },
  (error) => Promise.reject(error)
);

// ======================
// RESPONSE INTERCEPTOR
// ======================
apiClient.interceptors.response.use(
  (response) => response,

  (error) => {
    const status = error?.response?.status;

    // AUTO LOGOUT
    if (status === 401) {
      authService.clearAuth();

      if (window.location.pathname !== "/login") {
        window.location.href = "/login";
      }
    }

    console.error("API ERROR:", {
      url: error?.config?.url,
      method: error?.config?.method,
      status,
      data: error?.response?.data,
    });

    return Promise.reject(error);
  }
);

// ======================
// ROLE HOME ROUTES
// ======================
const getDefaultRouteByRole = (role) => {
  const normalized = normalizeRole(role);

  switch (normalized) {
    case "SUPER_ADMIN":
      return "/app/super-admin";

    case "SCHOOL_ADMIN":
      return "/app/dashboard";

    case "TEACHER":
      return "/app/teacher-portal";

    case "FINANCE":
      return "/app/finance-portal";

    case "SECRETARY":
      return "/app/secretary-portal";

    case "STUDENT":
      return "/app/student-portal";

    default:
      return "/app/dashboard";
  }
};

// ======================
// ROLE ACCESS MAP
// ======================
const routePermissions = {
  dashboard: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
    "TEACHER",
    "FINANCE",
    "SECRETARY",
  ],

  students: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
  ],

  staff: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],

  fees: [
    "SCHOOL_ADMIN",
    "FINANCE",
  ],

  attendance: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "SECRETARY",
  ],

  exams: [
    "SCHOOL_ADMIN",
    "TEACHER",
  ],

  timetable: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "STUDENT",
  ],

  inventory: [
    "SCHOOL_ADMIN",
    "SECRETARY",
  ],

  announcements: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
    "FINANCE",
    "STUDENT",
  ],

  "teacher-portal": [
    "TEACHER",
    "SCHOOL_ADMIN",
  ],

  "finance-portal": [
    "FINANCE",
    "SCHOOL_ADMIN",
  ],

  "secretary-portal": [
    "SECRETARY",
    "SCHOOL_ADMIN",
  ],

  "student-portal": [
    "STUDENT",
  ],

  "super-admin": [
    "SUPER_ADMIN",
  ],

  // ======================
  // LOGIN PORTAL
  // ======================
  "login-portal": [
    "SCHOOL_ADMIN",
  ],

  debug: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],
};

// ======================
// PROTECTED ROUTE
// ======================
const ProtectedRoute = () => {
  const token = authService.getToken();

  if (!token) {
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;
};

// ======================
// ROLE PROTECTION
// ======================
const RoleProtectedRoute = ({
  routeKey,
  children,
}) => {
  const role = authService.getRole();

  const allowedRoles =
    routePermissions[routeKey] || [];

  if (!allowedRoles.includes(role)) {
    return (
      <Navigate
        to={getDefaultRouteByRole(role)}
        replace
      />
    );
  }

  return children;
};

// ======================
// SMART ROOT REDIRECT
// ======================
const AppRootRedirect = () => {
  const role = authService.getRole();

  return (
    <Navigate
      to={getDefaultRouteByRole(role)}
      replace
    />
  );
};

// ======================
// SAFE LAYOUT WRAPPER
// ======================
const SafeDashboardLayout = () => {
  const location = useLocation();

  const user = useMemo(() => {
    return authService.getUser();
  }, []);

  // Prevent blank dashboard crashes
  if (!user) {
    authService.clearAuth();

    return <Navigate to="/login" replace />;
  }

  return (
    <DashboardLayout
      key={location.pathname}
      currentUser={user}
    />
  );
};

// ======================
// APP
// ======================
function App() {
  return (
    <div className="App">
      <BrowserRouter>

        <Routes>

          {/* ========================= */}
          {/* PUBLIC ROUTES */}
          {/* ========================= */}

          <Route
            path="/"
            element={<LandingPage />}
          />

          <Route
            path="/login"
            element={<LoginPage />}
          />

          <Route
            path="/register"
            element={<RegisterPage />}
          />

          <Route
            path="/register-school"
            element={<RegisterPage />}
          />

          <Route
            path="/setup-school"
            element={<SchoolProfilePage />}
          />

          <Route
            path="/join-school"
            element={<JoinSchoolPage />}
          />

          <Route
            path="/join/:inviteCode"
            element={<JoinSchoolPage />}
          />

          {/* ========================= */}
          {/* PROTECTED APP */}
          {/* ========================= */}

          <Route element={<ProtectedRoute />}>

            <Route
              path="/app"
              element={<SafeDashboardLayout />}
            >

              {/* SMART ROOT REDIRECT */}
              <Route
                index
                element={<AppRootRedirect />}
              />

              {/* DASHBOARD */}
              <Route
                path="dashboard"
                element={
                  <RoleProtectedRoute routeKey="dashboard">
                    <Dashboard />
                  </RoleProtectedRoute>
                }
              />

              {/* STUDENTS */}
              <Route
                path="students"
                element={
                  <RoleProtectedRoute routeKey="students">
                    <StudentsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* STAFF */}
              <Route
                path="staff"
                element={
                  <RoleProtectedRoute routeKey="staff">
                    <StaffPage />
                  </RoleProtectedRoute>
                }
              />

              {/* FEES */}
              <Route
                path="fees"
                element={
                  <RoleProtectedRoute routeKey="fees">
                    <FeesPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ATTENDANCE */}
              <Route
                path="attendance"
                element={
                  <RoleProtectedRoute routeKey="attendance">
                    <AttendancePage />
                  </RoleProtectedRoute>
                }
              />

              {/* EXAMS */}
              <Route
                path="exams"
                element={
                  <RoleProtectedRoute routeKey="exams">
                    <ExamsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* TIMETABLE */}
              <Route
                path="timetable"
                element={
                  <RoleProtectedRoute routeKey="timetable">
                    <TimetablePage />
                  </RoleProtectedRoute>
                }
              />

              {/* INVENTORY */}
              <Route
                path="inventory"
                element={
                  <RoleProtectedRoute routeKey="inventory">
                    <InventoryPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ANNOUNCEMENTS */}
              <Route
                path="announcements"
                element={
                  <RoleProtectedRoute routeKey="announcements">
                    <AnnouncementsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* LOGIN PORTAL */}
              <Route
                path="login-portal"
                element={
                  <RoleProtectedRoute routeKey="login-portal">
                    <LoginPortalPage />
                  </RoleProtectedRoute>
                }
              />

              {/* STUDENT PORTAL */}
              <Route
                path="student-portal"
                element={
                  <RoleProtectedRoute routeKey="student-portal">
                    <StudentPortal />
                  </RoleProtectedRoute>
                }
              />

              {/* TEACHER PORTAL */}
              <Route
                path="teacher-portal"
                element={
                  <RoleProtectedRoute routeKey="teacher-portal">
                    <TeacherPortal />
                  </RoleProtectedRoute>
                }
              />

              {/* FINANCE PORTAL */}
